  1→/**
  2→ * WebSocket Query Protocol Client
  3→ *
  4→ * Singleton client that connects to the backend's /ws endpoint and handles
  5→ * the q:* protocol for real-time data subscriptions, one-shot requests,
  6→ * mutations, and async commands.
  7→ *
  8→ * Protocol:
  9→ *   Client sends: q:subscribe, q:unsubscribe, q:request, q:mutate, q:command
 10→ *   Server sends: q:snapshot, q:delta, q:response, q:mutate_result, q:command_ack, q:error, q:event, ping
 11→ *   Client responds to ping with pong
 12→ *
 13→ * Relay mode (web-production):
 14→ *   Connects through cloud relay at wss://relay.rundeus.com/api/servers/{id}/connect
 15→ *   Sends { type: "authenticate", token } on open for device token auth.
 16→ *   Handles relay control frames: authenticated, auth_failed, server_reconnecting, server_connected.
 17→ *
 18→ * On reconnect, all active subscriptions are re-established automatically.
 19→ */
 20→
 21→import { match } from "ts-pattern";
 22→import { resolveBackendEndpoints, isRelayMode } from "@/shared/config/backend.config";
 23→import { getStoredToken, signOut } from "@/features/auth";
 24→import type { QueryResource, CommandName } from "@shared/types/query-protocol";
 25→
 26→// ---- Types ----
 27→
 28→type SnapshotCallback = (data: unknown) => void;
 29→type DeltaCallback = (upserted?: unknown[], removed?: string[], cursor?: number) => void;
 30→type EventCallback = (event: string, data: unknown) => void;
 31→
 32→interface PendingCommand {
 33→  resolve: (result: { accepted: boolean; commandId?: string; error?: string }) => void;
 34→  reject: (err: Error) => void;
 35→}
 36→
 37→interface PendingRequest {
 38→  resolve: (data: unknown) => void;
 39→  reject: (err: Error) => void;
 40→  timer: ReturnType<typeof setTimeout>;
 41→}
 42→
 43→interface PendingMutation {
 44→  resolve: (result: { success: boolean; data?: unknown; error?: string }) => void;
 45→  reject: (err: Error) => void;
 46→  timer: ReturnType<typeof setTimeout>;
 47→}
 48→
 49→interface Subscription {
 50→  id: string;
 51→  resource: QueryResource;
 52→  params?: Record<string, unknown>;
 53→  onSnapshot: SnapshotCallback;
 54→  onDelta?: DeltaCallback;
 55→}
 56→
 57→// ---- Reconnect Config ----
 58→
 59→const BACKOFF_BASE_MS = 500;
 60→const BACKOFF_MAX_MS = 8000;
 61→
 62→// ---- Singleton State ----
 63→
 64→let ws: WebSocket | null = null;
 65→let _connectionId: string | null = null;
 66→let connected = false;
 67→let connecting = false;
 68→let reconnectAttempt = 0;
 69→let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 70→let subCounter = 0;
 71→
 72→/** Active subscriptions keyed by client-assigned ID. */
 73→const subscriptions = new Map<string, Subscription>();
 74→
 75→/** Pending commands waiting for q:command_ack. */
 76→const pendingCommands = new Map<string, PendingCommand>();
 77→
 78→/** Pending one-shot q:request frames waiting for q:response. */
 79→const pendingRequests = new Map<string, PendingRequest>();
 80→
 81→/** Pending q:mutate frames waiting for q:mutate_result. */
 82→const pendingMutations = new Map<string, PendingMutation>();
 83→
 84→/** Listeners for q:event broadcasts. */
 85→const eventListeners = new Set<EventCallback>();
 86→
 87→/** Listeners notified when connection state changes (connected/disconnected). */
 88→const connectionChangeListeners = new Set<(connected: boolean) => void>();
 89→
 90→/** Counter for generating unique command frame IDs. */
 91→let commandCounter = 0;
 92→
 93→/** Counter for generating unique request/mutation frame IDs. */
 94→let requestCounter = 0;
 95→
 96→/** Resolvers waiting for the initial "connected" frame after open. */
 97→let connectResolve: (() => void) | null = null;
 98→let connectReject: ((err: Error) => void) | null = null;
 99→
100→// ---- Public API ----
101→
102→/** Generate a unique subscription ID. */
103→function nextSubId(): string {
104→  return `sub_${++subCounter}`;
105→}
106→
107→/**
108→ * Connect to the backend WebSocket. Resolves once authenticated.
109→ * No-op if already connected or connecting.
110→ *
111→ * In relay mode, pass the serverId so the WS URL can be resolved.
112→ */
113→export async function connect(serverId?: string): Promise<void> {
114→  // Detect stale socket: `connected` flag says yes but the actual WebSocket is dead.
115→  // This happens after Vite HMR reloads — module state is preserved but the socket
116→  // reference is stale (readyState !== OPEN). Force reconnect in this case.
117→  if (connected && (!ws || ws.readyState !== WebSocket.OPEN)) {
118→    connected = false;
119→    connecting = false;
120→    _connectionId = null;
121→    if (ws) {
122→      const staleWs = ws;
123→      ws = null;
124→      staleWs.onclose = null;
125→      try {
126→        staleWs.close();
127→      } catch {
128→        /* ignore */
129→      }
130→    }
131→    notifyConnectionChange(false);
132→  }
133→  if (connected) return;
134→  if (connecting) {
135→    // Wait for the in-flight connection attempt
136→    return new Promise<void>((resolve, reject) => {
137→      const prevResolve = connectResolve;
138→      const prevReject = connectReject;
139→      connectResolve = () => {
140→        prevResolve?.();
141→        resolve();
142→      };
143→      connectReject = (err) => {
144→        prevReject?.(err);
145→        reject(err);
146→      };
147→    });
148→  }
149→
150→  connecting = true;
151→
152→  return new Promise<void>((resolve, reject) => {
153→    connectResolve = resolve;
154→    connectReject = reject;
155→    openSocket(serverId).catch((err) => {
156→      connecting = false;
157→      connectReject?.(err);
158→      connectResolve = null;
159→      connectReject = null;
160→    });
161→  });
162→}
163→
164→/**
165→ * Subscribe to a query resource. Returns an unsubscribe function.
166→ *
167→ * On subscription, the server sends an initial q:snapshot. Subsequent
168→ * invalidations push q:snapshot (full replace) or q:delta (incremental).
169→ */
170→export function subscribe(
171→  resource: QueryResource,
172→  params: Record<string, unknown> | undefined,
173→  onSnapshot: SnapshotCallback,
174→  onDelta?: DeltaCallback
175→): () => void {
176→  const id = nextSubId();
177→  const sub: Subscription = { id, resource, params, onSnapshot, onDelta };
178→  subscriptions.set(id, sub);
179→
180→  // If connected, send subscribe frame immediately
181→  if (connected && ws) {
182→    sendFrame({
183→      type: "q:subscribe",
184→      id,
185→      resource,
186→      ...(params ? { params } : {}),
187→    });
188→  }
189→
190→  // Return unsubscribe function
191→  return () => {
192→    subscriptions.delete(id);
193→    if (connected && ws) {
194→      sendFrame({ type: "q:unsubscribe", id });
195→    }
196→  };
197→}
198→
199→/** Check if the client is currently connected. */
200→export function isConnected(): boolean {
201→  return connected;
202→}
203→
204→/**
205→ * Send an async command via the q:command frame.
206→ * Returns a promise that resolves when the server sends q:command_ack.
207→ * @param timeoutMs — override default 30s timeout (e.g. 300_000 for long-running commands like git:clone)
208→ */
209→export function sendCommand(
210→  command: CommandName,
211→  params: Record<string, unknown>,
212→  timeoutMs = 30_000
213→): Promise<{ accepted: boolean; commandId?: string; error?: string }> {
214→  const id = `cmd_${++commandCounter}`;
215→
216→  return new Promise((resolve, reject) => {
217→    pendingCommands.set(id, { resolve, reject });
218→
219→    const sent = sendFrame({
220→      type: "q:command",
221→      id,
222→      command,
223→      params,
224→    });
225→
226→    // Reject immediately if the frame couldn't be sent (WS disconnected)
227→    if (!sent) {
228→      pendingCommands.delete(id);
229→      reject(new Error("WebSocket not connected"));
230→      return;
231→    }
232→
233→    // Timeout to prevent leaked promises
234→    setTimeout(() => {
235→      if (pendingCommands.has(id)) {
236→        pendingCommands.delete(id);
237→        reject(new Error(`Command ${command} timed out`));
238→      }
239→    }, timeoutMs);
240→  });
241→}
242→
243→/**
244→ * Send a one-shot data request via the q:request frame.
245→ * Returns a promise that resolves with the response data when the
246→ * server sends q:response, or rejects on q:error or timeout.
247→ *
248→ * Works with both subscribable (QueryResource) and request-only
249→ * (RequestResource) resources.
250→ */
251→export function sendRequest<T = unknown>(
252→  resource: string,
253→  params?: Record<string, unknown>
254→): Promise<T> {
255→  const id = `req_${++requestCounter}`;
256→  const REQUEST_TIMEOUT_MS = 30_000;
257→
258→  return new Promise<T>((resolve, reject) => {
259→    const timer = setTimeout(() => {
260→      pendingRequests.delete(id);
261→      reject(new Error(`Request ${resource} timed out`));
262→    }, REQUEST_TIMEOUT_MS);
263→
264→    pendingRequests.set(id, {
265→      resolve: resolve as (data: unknown) => void,
266→      reject,
267→      timer,
268→    });
269→
270→    const sent = sendFrame({
271→      type: "q:request",
272→      id,
273→      resource,
274→      ...(params ? { params } : {}),
275→    });
276→
277→    if (!sent) {
278→      clearTimeout(timer);
279→      pendingRequests.delete(id);
280→      reject(new Error("WebSocket not connected"));
281→    }
282→  });
283→}
284→
285→/**
286→ * Send a mutation via the q:mutate frame.
287→ * Returns a promise that resolves with the mutation result when the
288→ * server sends q:mutate_result, or rejects on timeout.
289→ */
290→export function sendMutate<T = unknown>(
291→  action: string,
292→  params: Record<string, unknown>
293→): Promise<{ success: boolean; data?: T; error?: string }> {
294→  const id = `mut_${++requestCounter}`;
295→  const MUTATE_TIMEOUT_MS = 30_000;
296→
297→  return new Promise((resolve, reject) => {
298→    const timer = setTimeout(() => {
299→      pendingMutations.delete(id);
300→      reject(new Error(`Mutation ${action} timed out`));
301→    }, MUTATE_TIMEOUT_MS);
302→
303→    pendingMutations.set(id, {
304→      resolve: resolve as (result: { success: boolean; data?: unknown; error?: string }) => void,
305→      reject,
306→      timer,
307→    });
308→
309→    const sent = sendFrame({
310→      type: "q:mutate",
311→      id,
312→      action,
313→      params,
314→    });
315→
316→    if (!sent) {
317→      clearTimeout(timer);
318→      pendingMutations.delete(id);
319→      reject(new Error("WebSocket not connected"));
320→    }
321→  });
322→}
323→
324→/**
325→ * Register a callback for q:event broadcasts.
326→ * Returns an unregister function.
327→ */
328→export function onEvent(callback: EventCallback): () => void {
329→  eventListeners.add(callback);
330→  return () => {
331→    eventListeners.delete(callback);
332→  };
333→}
334→
335→/**
336→ * Send a tool response back to the backend (q:tool_response frame).
337→ * Used by frontend RPC handlers to respond to tool relay requests
338→ * received via q:event with event: "tool:request".
339→ */
340→export function sendToolResponse(requestId: string, result?: unknown, error?: string): boolean {
341→  const frame: Record<string, unknown> = {
342→    type: "q:tool_response",
343→    requestId,
344→  };
345→  if (error !== undefined) {
346→    frame.error = error;
347→  } else {
348→    frame.result = result;
349→  }
350→  return sendFrame(frame);
351→}
352→
353→/**
354→ * Force an immediate reconnection to the backend.
355→ * Used when the backend restarts on a new port — cancels any pending
356→ * backoff timer and closes the stale socket so reconnection picks up
357→ * the new port from getBackendPort().
358→ */
359→export function forceReconnect(): void {
360→  // Cancel any pending reconnect timer so we don't double-connect
361→  if (reconnectTimer) {
362→    clearTimeout(reconnectTimer);
363→    reconnectTimer = null;
364→  }
365→
366→  // Reset backoff counter so the immediate attempt uses minimal delay
367→  reconnectAttempt = 0;
368→
369→  // Close existing socket (if open) — onclose handler will NOT auto-schedule
370→  // because we immediately trigger our own reconnect below.
371→  if (ws) {
372→    // Prevent the onclose handler from scheduling its own reconnect
373→    const staleWs = ws;
374→    ws = null;
375→    connected = false;
376→    connecting = false;
377→    _connectionId = null;
378→    staleWs.onclose = null;
379→    staleWs.close();
380→
381→    notifyConnectionChange(false);
382→  }
383→
384→  // Immediately open a new socket (reads fresh port from getBackendPort())
385→  connecting = true;
386→  openSocket().catch(() => {
387→    connecting = false;
388→    // If this fails, fall back to normal backoff reconnect
389→    scheduleReconnect();
390→  });
391→}
392→
393→/**
394→ * Register a callback for connection state changes.
395→ * Fires with `true` when connected, `false` when disconnected.
396→ * Used by useQuerySubscription to re-evaluate subscriptions after reconnect.
397→ * Returns an unregister function.
398→ */
399→export function onConnectionChange(callback: (connected: boolean) => void): () => void {
400→  connectionChangeListeners.add(callback);
401→  return () => {
402→    connectionChangeListeners.delete(callback);
403→  };
404→}
405→
406→// ---- Internal ----
407→
408→async function openSocket(serverId?: string): Promise<void> {
409→  const endpoints = await resolveBackendEndpoints(serverId);
410→  const url = endpoints.wsUrl;
411→  const relay = isRelayMode();
412→
413→  ws = new WebSocket(url);
414→
415→  ws.onopen = () => {
416→    if (relay) {
417→      // Relay mode: send authenticate frame with device token
418→      const token = getStoredToken();
419→      if (token) {
420→        sendFrame({ type: "authenticate", token });
421→      } else {
422→        // No token available — close and surface auth failure
423→        console.error("[WS] Relay mode: no device token available for authentication");
424→        ws?.close(4001, "No device token");
425→      }
426→    }
427→    // Localhost/web-dev connections are auto-authenticated by the backend.
428→    // Wait for the "connected" frame in onmessage.
429→  };
430→
431→  ws.onmessage = (evt) => {
432→    let msg: Record<string, unknown>;
433→    try {
434→      msg = JSON.parse(evt.data as string);
435→    } catch {
436→      return;
437→    }
438→
439→    const type = typeof msg.type === "string" ? msg.type : "";
440→
441→    match(type)
442→      .with("connected", () => {
443→        // Localhost/web-dev: backend sends "connected" after auto-auth
444→        _connectionId = msg.connectionId as string;
445→        connected = true;
446→        connecting = false;
447→        reconnectAttempt = 0;
448→
449→        resubscribeAll();
450→        notifyConnectionChange(true);
451→
452→        connectResolve?.();
453→        connectResolve = null;
454→        connectReject = null;
455→      })
456→      .with("authenticated", () => {
457→        // Relay mode: relay confirms device token is valid
458→        connected = true;
459→        connecting = false;
460→        reconnectAttempt = 0;
461→
462→        resubscribeAll();
463→        notifyConnectionChange(true);
464→
465→        connectResolve?.();
466→        connectResolve = null;
467→        connectReject = null;
468→      })
469→      .with("auth_failed", () => {
470→        // Relay mode: device token rejected — sign out (clears storage + React state)
471→        console.error("[WS] Relay auth failed:", msg.message);
472→        signOut();
473→
474→        // Prevent the onclose handler from triggering a reconnect loop
475→        connected = false;
476→        subscriptions.clear();
477→        if (ws) {
478→          ws.onclose = null;
479→          ws.close(4001, "Auth failed");
480→          ws = null;
481→        }
482→
483→        connecting = false;
484→        connectReject?.(new Error(`Relay auth failed: ${msg.message}`));
485→        connectResolve = null;
486→        connectReject = null;
487→
488→        notifyConnectionChange(false);
489→      })
490→      .with("server_reconnecting", () => {
491→        // Relay mode: desktop server disconnected from relay, waiting for reconnect.
492→        // Mark as disconnected so isConnected() returns false — q:request/q:mutate
493→        // will reject immediately instead of sending frames that will time out.
494→        // Keep the WS open — relay will send "server_connected" when server returns.
495→        if (import.meta.env.DEV) {
496→          console.log("[WS] Server reconnecting (relay):", msg);
497→        }
498→        connected = false;
499→
500→        // Reject all pending one-shot requests and mutations
501→        for (const [_id, pending] of pendingRequests) {
502→          clearTimeout(pending.timer);
503→          pending.reject(new Error("Server disconnected — reconnecting"));
504→        }
505→        pendingRequests.clear();
506→
507→        for (const [_id, pending] of pendingMutations) {
508→          clearTimeout(pending.timer);
509→          pending.reject(new Error("Server disconnected — reconnecting"));
510→        }
511→        pendingMutations.clear();
512→
513→        notifyConnectionChange(false);
514→      })
515→      .with("server_connected", () => {
516→        // Relay mode: desktop server reconnected to relay.
517→        // Re-subscribe all active subscriptions.
518→        if (import.meta.env.DEV) {
519→          console.log("[WS] Server reconnected (relay)");
520→        }
521→        connected = true;
522→        resubscribeAll();
523→        notifyConnectionChange(true);
524→      })
525→      .with("ping", () => {
526→        sendFrame({ type: "pong" });
527→      })
528→      .with("q:snapshot", () => {
529→        const sub = subscriptions.get(msg.id as string);
530→        sub?.onSnapshot(msg.data);
531→      })
532→      .with("q:delta", () => {
533→        const sub = subscriptions.get(msg.id as string);
534→        sub?.onDelta?.(
535→          msg.upserted as unknown[] | undefined,
536→          msg.removed as string[] | undefined,
537→          msg.cursor as number | undefined
538→        );
539→      })
540→      .with("q:command_ack", () => {
541→        const pending = pendingCommands.get(msg.id as string);
542→        if (pending) {
543→          pendingCommands.delete(msg.id as string);
544→          pending.resolve({
545→            accepted: msg.accepted as boolean,
546→            commandId: msg.commandId as string | undefined,
547→            error: msg.error as string | undefined,
548→          });
549→        }
550→      })
551→      .with("q:event", () => {
552→        const event = msg.event as string;
553→        const data = msg.data;
554→        for (const cb of eventListeners) {
555→          try {
556→            cb(event, data);
557→          } catch (err) {
558→            console.error("[WS] Event listener error:", err);
559→          }
560→        }
561→      })
562→      .with("q:response", () => {
563→        // One-shot q:request response
564→        const id = msg.id as string;
565→        const pending = pendingRequests.get(id);
566→        if (pending) {
567→          clearTimeout(pending.timer);
568→          pendingRequests.delete(id);
569→          pending.resolve(msg.data);
570→        }
571→      })
572→      .with("q:mutate_result", () => {
573→        // Mutation result
574→        const id = msg.id as string;
575→        const pending = pendingMutations.get(id);
576→        if (pending) {
577→          clearTimeout(pending.timer);
578→          pendingMutations.delete(id);
579→          pending.resolve({
580→            success: msg.success as boolean,
581→            data: msg.data as unknown,
582→            error: msg.error as string | undefined,
583→          });
584→        }
585→      })
586→      .with("q:error", () => {
587→        const id = msg.id as string;
588→        const errorMsg = (msg.message as string) || "Query error";
589→
590→        // Check if this error is for a pending request
591→        const pendingReq = pendingRequests.get(id);
592→        if (pendingReq) {
593→          clearTimeout(pendingReq.timer);
594→          pendingRequests.delete(id);
595→          pendingReq.reject(new Error(errorMsg));
596→          return;
597→        }
598→
599→        // Check if this error is for a pending mutation
600→        const pendingMut = pendingMutations.get(id);
601→        if (pendingMut) {
602→          clearTimeout(pendingMut.timer);
603→          pendingMutations.delete(id);
604→          pendingMut.reject(new Error(errorMsg));
605→          return;
606→        }
607→
608→        // Subscription error (existing behavior)
609→        console.warn("[WS] Query error:", msg.message, "for sub:", id);
610→      })
611→      .otherwise(() => {
612→        // Ignore unknown frame types
613→      });
614→  };
615→
616→  ws.onerror = () => {
617→    // onerror fires before onclose — actual cleanup happens in onclose
618→  };
619→
620→  ws.onclose = () => {
621→    const wasConnected = connected;
622→    connected = false;
623→    _connectionId = null;
624→    ws = null;
625→
626→    // Reject all pending commands immediately — they can't succeed without a connection
627→    for (const [_id, pending] of pendingCommands) {
628→      pending.reject(new Error("WebSocket disconnected"));
629→    }
630→    pendingCommands.clear();
631→
632→    // Reject all pending one-shot requests
633→    for (const [_id, pending] of pendingRequests) {
634→      clearTimeout(pending.timer);
635→      pending.reject(new Error("WebSocket disconnected — request failed"));
636→    }
637→    pendingRequests.clear();
638→
639→    // Reject all pending mutations
640→    for (const [_id, pending] of pendingMutations) {
641→      clearTimeout(pending.timer);
642→      pending.reject(new Error("WebSocket disconnected — mutation failed"));
643→    }
644→    pendingMutations.clear();
645→
646→    if (connecting) {
647→      // Initial connection failed — reject the connect() promise
648→      connecting = false;
649→      connectReject?.(new Error("WebSocket connection failed"));
650→      connectResolve = null;
651→      connectReject = null;
652→    }
653→
654→    if (wasConnected) {
655→      notifyConnectionChange(false);
656→    }
657→
658→    // Only auto-reconnect if we had previously connected or have active subscriptions
659→    if (wasConnected || subscriptions.size > 0) {
660→      scheduleReconnect();
661→    }
662→  };
663→}
664→
665→/** Notify all connection change listeners. */
666→function notifyConnectionChange(state: boolean): void {
667→  for (const cb of connectionChangeListeners) {
668→    try {
669→      cb(state);
670→    } catch (err) {
671→      console.error("[WS] Connection change listener error:", err);
672→    }
673→  }
674→}
675→
676→function sendFrame(frame: Record<string, unknown>): boolean {
677→  if (ws && ws.readyState === WebSocket.OPEN) {
678→    try {
679→      ws.send(JSON.stringify(frame));
680→      return true;
681→    } catch {
682→      // Connection may have closed between readyState check and send
683→      console.warn(`[WS] Failed to send ${frame.type} frame: connection closed during send`);
684→      return false;
685→    }
686→  }
687→  console.warn(`[WS] Dropped ${frame.type} frame: WebSocket not connected`);
688→  return false;
689→}
690→
691→/** Re-subscribe all active subscriptions after reconnect. */
692→function resubscribeAll(): void {
693→  for (const sub of subscriptions.values()) {
694→    sendFrame({
695→      type: "q:subscribe",
696→      id: sub.id,
697→      resource: sub.resource,
698→      ...(sub.params ? { params: sub.params } : {}),
699→    });
700→  }
701→}
702→
703→/** Schedule a reconnection with exponential backoff. */
704→function scheduleReconnect(): void {
705→  if (reconnectTimer) return;
706→
707→  const delay = Math.min(BACKOFF_BASE_MS * Math.pow(2, reconnectAttempt), BACKOFF_MAX_MS);
708→  reconnectAttempt++;
709→
710→  if (import.meta.env.DEV) {
711→    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})`);
712→  }
713→
714→  reconnectTimer = setTimeout(() => {
715→    reconnectTimer = null;
716→    connecting = true;
717→
718→    // Set up resolve/reject so subscriptions get re-established
719→    connectResolve = null;
720→    connectReject = null;
721→
722→    openSocket().catch(() => {
723→      connecting = false;
724→      // onclose handler will schedule another reconnect
725→    });
726→  }, delay);
727→}
