file.content:
.hero-demo-metric-value.wide {
  width: 65px;
}

/* Table */
.hero-demo-table {
  flex: 1;
  background: white;
  border-radius: 8px;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.04);
  overflow: hidden;
}

.hero-demo-table-header {
  display: flex;
  padding: 10px 14px;
  border-bottom: 1px solid rgba(0, 0, 0, 0.06);
  gap: 20px;
}

.hero-demo-th {
  height: 6px;
  background: rgba(0, 0, 0, 0.1);
  border-radius: 2px;
}

.hero-demo-table-row {
  display: flex;
  padding: 12px 14px;
  border-bottom: 1px solid rgba(0, 0, 0, 0.04);
  gap: 20px;
  align-items: center;
}

.hero-demo-td {
  height: 7px;
  background: rgba(0, 0, 0, 0.06);
  border-radius: 2px;
}

.hero-demo-td-pill {
  width: 48px;
  height: 18px;
  background: rgba(0, 0, 0, 0.04);
  border-radius: 9px;
}

.hero-demo-button-highlight {
  position: absolute;
  border: 2px solid rgba(59, 130, 246, 0.7);
  border-radius: 8px;
  background: transparent;
  opacity: 0;
  transform: scale(0.98);
  transition: opacity 0.12s ease-out, transform 0.12s ease-out;
  pointer-events: none;
  box-sizing: border-box;
}

.hero-demo-button-highlight.visible {
  opacity: 1;
  transform: scale(1);
}

/* Drag selection box - dashed style like FeaturesDemo */
.hero-demo-drag-box {
  position: absolute;
  border: 1.5px dashed #22c55e;
  border-radius: 8px;
  background: rgba(34, 197, 94, 0.08);
  pointer-events: none;
  z-index: 45;
}

/* Area outline - stays visible after drag */
.hero-demo-area-outline {
  position: absolute;
  border: 2px dashed #22c55e;
  border-radius: 8px;
  opacity: 0;
  transition: opacity 0.15s ease;
  pointer-events: none;
  background: rgba(34, 197, 94, 0.05);
  z-index: 44;
}

.hero-demo-area-outline.visible {
  opacity: 1;
}

/* Cursor */
.hero-demo-cursor {
  position: absolute;
  pointer-events: none;
  z-index: 100;
  transition: left 0.35s cubic-bezier(0.4, 0, 0.2, 1), top 0.35s cubic-bezier(0.4, 0, 0.2, 1);
  display: grid;
}

.hero-demo-cursor.dragging {
  transition: none;
}

.hero-demo-cursor.dragging * {
  transition: none !important;
}

.hero-demo-cursor-pointer,
.hero-demo-cursor-crosshair,
.hero-demo-cursor-ibeam {
  grid-area: 1 / 1;
  transform: scale(1);
  transform-origin: top left;
  transition: transform 0.2s ease, opacity 0.2s ease;
}

.hero-demo-cursor-pointer.hidden {
  transform: scale(0);
  opacity: 0;
}

.hero-demo-cursor-crosshair.hidden {
  transform: scale(0);
  opacity: 0;
}

.hero-demo-cursor-ibeam.hidden {
  transform: scale(0);
  opacity: 0;
}

.hero-demo-cursor-ibeam {
  transform-origin: center center;
}

.hero-demo-cursor svg {
  display: block;
  filter: drop-shadow(0 1px 2px rgba(0, 0, 0, 0.3));
}

/* Toolbar - dark mode */
.hero-demo-toolbar {
  position: absolute;
  bottom: 12px;
  right: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #1a1a1a;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.25), 0 4px 16px rgba(0, 0, 0, 0.15);
  transition: width 0.4s cubic-bezier(0.19, 1, 0.22, 1), border-radius 0.4s cubic-bezier(0.19, 1, 0.22, 1), padding 0.4s cubic-bezier(0.19, 1, 0.22, 1), transform 0.15s ease, background 0.15s ease;
  width: 36px;
  height: 36px;
  border-radius: 18px;
}

.hero-demo-toolbar.hovered:not(.expanded) {
  background: #2a2a2a;
  transform: scale(1.05);
}

.hero-demo-toolbar.clicking:not(.expanded) {
  background: #333;
  transform: scale(0.95);
}

.hero-demo-toolbar.expanded {
  width: 200px;
  border-radius: 20px;
  padding: 0 6px 0 6px;
  justify-content: flex-start;
}

.hero-demo-toolbar-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  color: rgba(255, 255, 255, 0.85);
}

.hero-demo-toolbar.expanded .hero-demo-toolbar-icon {
  display: none;
}

.hero-demo-toolbar-buttons {
  display: none;
  align-items: center;
  gap: 3px;
}

.hero-demo-toolbar.expanded .hero-demo-toolbar-buttons {
  display: flex;
}

.hero-demo-toolbar-btn {
  width: 28px;
  height: 28px;

