  1→import * as React from "react";
  2→import {
  3→  DndContext,
  4→  closestCenter,
  5→  KeyboardSensor,
  6→  MouseSensor,
  7→  TouchSensor,
  8→  useSensor,
  9→  useSensors,
 10→  DragEndEvent,
 11→} from "@dnd-kit/core";
 12→import {
 13→  arrayMove,
 14→  SortableContext,
 15→  sortableKeyboardCoordinates,
 16→  verticalListSortingStrategy,
 17→} from "@dnd-kit/sortable";
 18→import { FolderOpen } from "lucide-react";
 19→import { Sidebar, SidebarContent, SidebarMenu, useSidebar } from "@/components/ui/sidebar";
 20→import { useUIStore } from "@/shared/stores/uiStore";
 21→import { useSidebarStore } from "../store/sidebarStore";
 22→import type { AppSidebarProps } from "../model/types";
 23→import { DraggableRepository } from "./DraggableRepository";
 24→import { SidebarHeader } from "./SidebarHeader";
 25→import { SidebarFooter } from "./SidebarFooter";
 26→
 27→export function AppSidebar({
 28→  repositories,
 29→  selectedWorkspaceId,
 30→  onWorkspaceClick,
 31→  onNewWorkspace,
 32→  onNewWorkspaceFromGitHub,
 33→  onAddRepository,
 34→  onCloneRepository,
 35→  onArchive,
 36→  onStatusChange,
 37→  onNewSession,
 38→  diffStatsMap,
 39→  profile = { username: "User" },
 40→}: AppSidebarProps) {
 41→  const { state, hoverOpen, toggleSidebar, isMobile, setOpenMobile } = useSidebar();
 42→  const openSettings = useUIStore((s) => s.openSettings);
 43→  const collapsedRepos = useSidebarStore((s) => s.collapsedRepos);
 44→  const toggleRepoCollapse = useSidebarStore((s) => s.toggleRepoCollapse);
 45→  const repositoryOrder = useSidebarStore((s) => s.repositoryOrder);
 46→  const setRepositoryOrder = useSidebarStore((s) => s.setRepositoryOrder);
 47→  const reorderRepositories = useSidebarStore((s) => s.reorderRepositories);
 48→
 49→  const isExpanded = state === "expanded" || hoverOpen;
 50→
 51→  // On mobile, close the sidebar sheet after selecting a workspace
 52→  const handleWorkspaceClick = React.useCallback(
 53→    (workspace: Parameters<typeof onWorkspaceClick>[0]) => {
 54→      onWorkspaceClick(workspace);
 55→      if (isMobile) setOpenMobile(false);
 56→    },
 57→    [onWorkspaceClick, isMobile, setOpenMobile]
 58→  );
 59→
 60→  // User's drag-drop order is the final word.
 61→  // Status is shown visually (badges, colors) — not by re-sorting after drag.
 62→  const orderedRepositories = React.useMemo(
 63→    () => reorderRepositories(repositories),
 64→    [repositories, repositoryOrder, reorderRepositories]
 65→  );
 66→
 67→  // Mouse: 5px distance differentiates click from drag
 68→  // Touch: 250ms long-press required before drag activates (allows normal scrolling)
 69→  const sensors = useSensors(
 70→    useSensor(MouseSensor, { activationConstraint: { distance: 5 } }),
 71→    useSensor(TouchSensor, { activationConstraint: { delay: 250, tolerance: 5 } }),
 72→    useSensor(KeyboardSensor, {
 73→      coordinateGetter: sortableKeyboardCoordinates,
 74→    })
 75→  );
 76→
 77→  /**
 78→   * Handle drag end - reorder repositories
 79→   */
 80→  function handleDragEnd(event: DragEndEvent) {
 81→    const { active, over } = event;
 82→
 83→    if (!over || active.id === over.id) {
 84→      return;
 85→    }
 86→
 87→    const oldIndex = orderedRepositories.findIndex((r) => r.repo_id === active.id);
 88→    const newIndex = orderedRepositories.findIndex((r) => r.repo_id === over.id);
 89→
 90→    if (oldIndex === -1 || newIndex === -1) {
 91→      return;
 92→    }
 93→
 94→    // Reorder array
 95→    const reordered = arrayMove(orderedRepositories, oldIndex, newIndex);
 96→
 97→    // Save new order to store
 98→    const newOrder = reordered.map((r) => r.repo_id);
 99→    setRepositoryOrder(newOrder);
100→  }
101→
102→  return (
103→    <Sidebar variant="inset" collapsible="offcanvas" className="p-0">
104→      <SidebarHeader
105→        profile={profile}
106→        onOpenSettings={openSettings}
107→        onToggleSidebar={toggleSidebar}
108→        onNewSession={onNewSession}
109→        isExpanded={isExpanded}
110→      />
111→
112→      {/* Repositories List or Empty State */}
113→      {repositories.length === 0 ? (
114→        <SidebarContent className="flex h-full items-center justify-center">
115→          <div className="flex flex-col items-center gap-3 px-6 text-center">
116→            <FolderOpen className="text-text-muted/30 h-10 w-10" strokeWidth={1.5} />
117→            <div className="space-y-1">
118→              <p className="text-text-secondary text-sm font-medium">No projects yet</p>
119→              <p className="text-text-muted text-xs">Add your first project to get started</p>
120→            </div>
121→          </div>
122→        </SidebarContent>
123→      ) : (
124→        <SidebarContent className="scrollbar-hidden">
125→          <DndContext
126→            sensors={sensors}
127→            collisionDetection={closestCenter}
128→            onDragEnd={handleDragEnd}
129→          >
130→            <SortableContext
131→              items={orderedRepositories.map((r) => r.repo_id)}
132→              strategy={verticalListSortingStrategy}
133→            >
134→              <SidebarMenu className="gap-1 px-1.5 py-2">
135→                {orderedRepositories.map((repo) => (
136→                  <DraggableRepository
137→                    key={repo.repo_id}
138→                    repository={repo}
139→                    isCollapsed={collapsedRepos.has(repo.repo_id)}
140→                    selectedWorkspaceId={selectedWorkspaceId}
141→                    onToggleCollapse={() => toggleRepoCollapse(repo.repo_id)}
142→                    onWorkspaceClick={handleWorkspaceClick}
143→                    onNewWorkspace={onNewWorkspace}
144→                    onNewWorkspaceFromGitHub={onNewWorkspaceFromGitHub}
145→                    onArchive={onArchive}
146→                    onStatusChange={onStatusChange}
147→                    diffStatsMap={diffStatsMap}
148→                    sidebarExpanded={isExpanded}
149→                    dragDisabled={!isExpanded}
150→                  />
151→                ))}
152→              </SidebarMenu>
153→            </SortableContext>
154→          </DndContext>
155→        </SidebarContent>
156→      )}
157→
158→      <SidebarFooter onAddRepository={onAddRepository} onCloneRepository={onCloneRepository} />
159→    </Sidebar>
160→  );
161→}
