 1→import { PanelLeftClose, SquarePen } from "lucide-react";
 2→import { SidebarHeader as SidebarHeaderUI, useSidebar } from "@/components/ui/sidebar";
 3→import { Avatar, AvatarFallback } from "@/components/ui/avatar";
 4→import { cn } from "@/shared/lib/utils";
 5→import type { SidebarHeaderProps } from "../model/types";
 6→
 7→/**
 8→ * SidebarHeader — V2: Jony Ive
 9→ *
10→ * Avatar + name. Subtle hover bg signals it's clickable.
11→ * No chevron — it promised a dropdown but delivered settings.
12→ */
13→export function SidebarHeader({
14→  profile = { username: "User" },
15→  onOpenSettings,
16→  onToggleSidebar,
17→  onNewSession,
18→  isExpanded,
19→}: SidebarHeaderProps) {
20→  const { isMobile } = useSidebar();
21→  const initials = profile.username.slice(0, 2).toUpperCase();
22→
23→  const modKey = typeof navigator !== "undefined" && /Mac/.test(navigator.platform) ? "⌘" : "Ctrl+";
24→  const toggleTitle = `${isExpanded ? "Collapse" : "Expand"} sidebar (${modKey}B)`;
25→
26→  return (
27→    <SidebarHeaderUI className="drag-region flex-row items-center justify-between gap-1 px-1.5 py-1.5">
28→      <button
29→        type="button"
30→        aria-label="Open settings"
31→        onClick={onOpenSettings}
32→        className="hover:bg-foreground/[0.04] flex min-w-0 flex-1 items-center gap-2 rounded-lg px-2 py-1.5 transition-colors duration-200"
33→      >
34→        <Avatar shape="square" className="h-6 w-6 shrink-0 rounded-md">
35→          <AvatarFallback shape="square" className="text-2xs rounded-md font-semibold">
36→            {initials}
