176→interface RepositoryWorkspaceListProps {
177→  repository: RepoGroup;
178→  isDeus: boolean;
179→  selectedWorkspaceId: string | null;
180→  unreadWorkspaceIds?: Set<string>;
181→  diffStatsMap?: Record<string, DiffStats>;
182→  reduceMotion: boolean | null;
183→  onNewWorkspace: (repoId?: string) => void;
184→  onWorkspaceClick: (workspace: Workspace) => void;
185→  onArchive?: (workspaceId: string) => void;
186→  onStatusChange?: (workspaceId: string, status: WorkspaceStatus) => void;
187→}
188→
189→function RepositoryWorkspaceList({
190→  repository,
191→  isDeus,
192→  selectedWorkspaceId,
193→  unreadWorkspaceIds,
194→  diffStatsMap,
195→  reduceMotion,
196→  onNewWorkspace,
197→  onWorkspaceClick,
198→  onArchive,
199→  onStatusChange,
200→}: RepositoryWorkspaceListProps) {
201→  const isExpanded = useSidebarStore((s) => s.expandedOldWorkspaces.has(repository.repo_id));
202→  const toggleOldWorkspaces = useSidebarStore((s) => s.toggleOldWorkspaces);
203→
204→  const sortedWorkspaces = sortByStatusPriority(
205→    repository.workspaces.filter((w) => w.state !== "archived"),
206→    unreadWorkspaceIds
207→  );
208→
209→  const [visible, stale] = splitByRecency(sortedWorkspaces, selectedWorkspaceId);
210→  const hasStale = stale.length > 0;
211→  const displayedWorkspaces = hasStale && !isExpanded ? visible : sortedWorkspaces;
212→
213→  return (
214→    <>
215→      {isDeus && (
216→        <m.li
217→          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
218→          animate={{ opacity: 1, y: 0 }}
219→          transition={{
220→            duration: 0.22,
221→            ease: [0.165, 0.84, 0.44, 1],
222→            delay: reduceMotion ? 0 : 0.02,
223→          }}
224→        >
225→          <DeusRepositoryBanner onNewWorkspace={() => onNewWorkspace(repository.repo_id)} />
226→        </m.li>
227→      )}
228→
229→      {sortedWorkspaces.length === 0 && (
230→        <m.li
231→          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
232→          animate={{ opacity: 1, y: 0 }}
233→          transition={{
234→            duration: 0.18,
235→            ease: [0.165, 0.84, 0.44, 1],
236→            delay: reduceMotion ? 0 : 0.03,
237→          }}
238→        >
239→          <SidebarRow
240→            variant="action"
241→            asChild
242→            onClick={() => onNewWorkspace(repository.repo_id)}
243→            className="text-text-tertiary hover:text-text-secondary w-full text-left text-base"
244→          >
245→            <button type="button">
246→              <SidebarRowMain>
247→                <SidebarRowIconSlot>
248→                  <Plus className="h-4 w-4" />
249→                </SidebarRowIconSlot>
250→                <span className="font-normal">New workspace</span>
251→              </SidebarRowMain>
252→            </button>
253→          </SidebarRow>
254→        </m.li>
255→      )}
256→
257→      {displayedWorkspaces.map((workspace, index) => (
258→        <m.li
259→          key={workspace.id}
260→          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
261→          animate={{ opacity: 1, y: 0 }}
262→          transition={{
263→            duration: 0.18,
264→            ease: [0.165, 0.84, 0.44, 1],
265→            delay: reduceMotion ? 0 : Math.min(0.05 + index * 0.025, 0.12),
266→          }}
267→        >
268→          <WorkspaceItem
269→            workspace={workspace}
270→            isActive={workspace.id === selectedWorkspaceId}
271→            diffStats={diffStatsMap?.[workspace.id]}
272→            onClick={onWorkspaceClick}
273→            onArchive={onArchive}
274→            onStatusChange={onStatusChange}
275→          />
276→        </m.li>
277→      ))}
278→
279→      {hasStale && (
280→        <m.li
281→          initial={reduceMotion ? false : { opacity: 0 }}
282→          animate={{ opacity: 1 }}
283→          transition={{ duration: 0.15, ease: [0.165, 0.84, 0.44, 1] }}
284→        >
285→          <SidebarRow
286→            variant="action"
287→            asChild
288→            className="text-text-muted hover:text-text-secondary w-full text-left"
289→          >
290→            <button type="button" onClick={() => toggleOldWorkspaces(repository.repo_id)}>
291→              <SidebarRowMain>
292→                <SidebarRowIconSlot>
293→                  <ChevronDown
294→                    className={cn(
295→                      "h-3.5 w-3.5 transition-transform duration-150",
296→                      isExpanded && "rotate-180"
297→                    )}
298→                  />
299→                </SidebarRowIconSlot>
300→                <span className="text-xs font-medium">
301→                  {isExpanded ? "Show less" : `Show ${stale.length} more`}
302→                </span>
303→              </SidebarRowMain>
304→            </button>
305→          </SidebarRow>
306→        </m.li>
307→      )}
308→    </>
309→  );
310→}
