250→                  "truncate text-xs",
251→                  isActiveState ? "text-text-tertiary" : "text-text-disabled"
252→                )}
253→              >
254→                {secondaryText}
255→              </span>
256→            )}
257→            {showStatusDot && (
258→              <span
259→                className={cn("text-xs", isActiveState ? "text-text-muted" : "text-text-disabled")}
260→              >
261→                ·
262→              </span>
263→            )}
264→            {statusText && (
