 17→import { cn } from "@/shared/lib/utils";
 18→import { Button } from "@/components/ui/button";
 19→import { Input } from "@/components/ui/input";
 20→import { Separator } from "@/components/ui/separator";
 21→import {
 22→  Sheet,
 23→  SheetContent,
 24→  SheetDescription,
 25→  SheetHeader,
 26→  SheetTitle,
 27→} from "@/components/ui/sheet";
 28→import { Skeleton } from "@/components/ui/skeleton";
 29→import { TooltipProvider } from "@/components/ui/tooltip";
 30→
 31→const SIDEBAR_COOKIE_NAME = "sidebar_state";
 32→const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7;
 33→const SIDEBAR_WIDTH = "16rem";
 34→const SIDEBAR_WIDTH_MOBILE = "calc(100vw - 3.5rem)";
 35→
 36→const SIDEBAR_KEYBOARD_SHORTCUT = "b";
 37→
 38→type SidebarContextProps = {
 39→  state: "expanded" | "collapsed";
 40→  open: boolean;
 41→  setOpen: (open: boolean) => void;
 42→  hoverOpen: boolean;
 43→  setHoverOpen: (open: boolean) => void;
 44→  openMobile: boolean;
 45→  setOpenMobile: (open: boolean) => void;
 46→  isMobile: boolean;
 47→  toggleSidebar: () => void;
 48→};
 49→
 50→const SidebarContext = React.createContext<SidebarContextProps | null>(null);
 51→
 52→function useSidebar() {
 53→  const context = React.useContext(SidebarContext);
 54→  if (!context) {
 55→    throw new Error("useSidebar must be used within a SidebarProvider.");
 56→  }
 57→
 58→  return context;
 59→}
 60→
 61→function SidebarProvider({
 62→  defaultOpen = true,
 63→  open: openProp,
 64→  onOpenChange: setOpenProp,
 65→  className,
 66→  style,
 67→  children,
 68→  ...props
 69→}: React.ComponentProps<"div"> & {
 70→  defaultOpen?: boolean;
 71→  open?: boolean;
 72→  onOpenChange?: (open: boolean) => void;
 73→}) {
 74→  const isMobile = useIsMobile();
 75→  const [openMobile, setOpenMobile] = React.useState(false);
 76→  const [hoverOpen, setHoverOpen] = React.useState(false);
 77→
 78→  // This is the internal state of the sidebar.
 79→  // We use openProp and setOpenProp for control from outside the component.
 80→  const [_open, _setOpen] = React.useState(defaultOpen);
 81→  const open = openProp ?? _open;
 82→  const setOpen = React.useCallback(
 83→    (value: boolean | ((value: boolean) => boolean)) => {
 84→      const openState = typeof value === "function" ? value(open) : value;
 85→      if (setOpenProp) {
 86→        setOpenProp(openState);
 87→      } else {
 88→        _setOpen(openState);
 89→      }
 90→
 91→      if (openState) {
 92→        setHoverOpen(false);
 93→      }
 94→
 95→      // This sets the cookie to keep the sidebar state.
 96→      document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`;
 97→    },
 98→    [setOpenProp, open]
 99→  );
100→
101→  // Helper to toggle the sidebar.
102→  const toggleSidebar = React.useCallback(() => {
103→    return isMobile ? setOpenMobile((open) => !open) : setOpen((open) => !open);
104→  }, [isMobile, setOpen, setOpenMobile]);
105→
106→  // Adds a keyboard shortcut to toggle the sidebar.
107→  React.useEffect(() => {
108→    const handleKeyDown = (event: KeyboardEvent) => {
109→      if (event.key === SIDEBAR_KEYBOARD_SHORTCUT && (event.metaKey || event.ctrlKey)) {
110→        event.preventDefault();
111→        toggleSidebar();
112→      }
113→    };
114→
115→    window.addEventListener("keydown", handleKeyDown);
116→    return () => window.removeEventListener("keydown", handleKeyDown);
117→  }, [toggleSidebar]);
118→
119→  const state = open ? "expanded" : "collapsed";
120→
121→  const contextValue = React.useMemo<SidebarContextProps>(
122→    () => ({
123→      state,
124→      open,
125→      setOpen,
126→      hoverOpen,
127→      setHoverOpen,
128→      isMobile,
129→      openMobile,
130→      setOpenMobile,
131→      toggleSidebar,
132→    }),
133→    [
134→      state,
135→      open,
136→      setOpen,
137→      hoverOpen,
138→      setHoverOpen,
139→      isMobile,
140→      openMobile,
141→      setOpenMobile,
142→      toggleSidebar,
143→    ]
144→  );
145→
146→  return (
147→    <SidebarContext.Provider value={contextValue}>
148→      <TooltipProvider delayDuration={0}>
149→        <div
150→          data-slot="sidebar-wrapper"
151→          style={
152→            {
153→              "--sidebar-width": SIDEBAR_WIDTH,
154→              ...style,
155→            } as React.CSSProperties
156→          }
157→          className={cn(
158→            "group/sidebar-wrapper has-data-[variant=inset]:bg-sidebar flex min-h-svh w-full",
159→            className
160→          )}
161→          {...props}
162→        >
163→          {children}
164→        </div>
165→      </TooltipProvider>
166→    </SidebarContext.Provider>
167→  );
168→}
169→
170→function Sidebar({
171→  side = "left",
172→  variant = "sidebar",
173→  collapsible = "offcanvas",
174→  className,
175→  children,
176→  ...props
177→}: React.ComponentProps<"div"> & {
178→  side?: "left" | "right";
179→  variant?: "sidebar" | "floating" | "inset";
180→  collapsible?: "offcanvas" | "icon" | "none";
181→}) {
182→  const { isMobile, state, open, hoverOpen, setHoverOpen, openMobile, setOpenMobile } =
183→    useSidebar();
184→  const hoverTimeoutRef = React.useRef<number | null>(null);
185→  const enableHoverReveal = !isMobile && collapsible === "offcanvas" && !open;
186→
187→  const clearHoverTimeout = React.useCallback(() => {
188→    if (hoverTimeoutRef.current !== null) {
189→      window.clearTimeout(hoverTimeoutRef.current);
190→      hoverTimeoutRef.current = null;
191→    }
192→  }, []);
193→
194→  const openHover = React.useCallback(() => {
195→    if (!enableHoverReveal) return;
196→    clearHoverTimeout();
197→    // Small delay to prevent accidental edge brushes from opening the sidebar.
198→    hoverTimeoutRef.current = window.setTimeout(() => setHoverOpen(true), 100);
199→  }, [clearHoverTimeout, enableHoverReveal, setHoverOpen]);
200→
201→  const closeHover = React.useCallback(() => {
202→    if (!enableHoverReveal) return;
203→    clearHoverTimeout();
204→    hoverTimeoutRef.current = window.setTimeout(() => setHoverOpen(false), 140);
205→  }, [clearHoverTimeout, enableHoverReveal, setHoverOpen]);
206→
207→  React.useEffect(() => {
208→    return () => clearHoverTimeout();
209→  }, [clearHoverTimeout]);
210→
211→  React.useEffect(() => {
212→    if (!open) return;
213→    clearHoverTimeout();
214→    if (hoverOpen) setHoverOpen(false);
215→  }, [open, hoverOpen, clearHoverTimeout, setHoverOpen]);
216→
217→  if (collapsible === "none") {
218→    return (
219→      <div
220→        data-slot="sidebar"
221→        data-sidebar="sidebar"
222→        className={cn(
223→          "bg-sidebar text-sidebar-foreground flex h-full w-(--sidebar-width) flex-col",
224→          className
225→        )}
226→        {...props}
227→      >
228→        {children}
229→      </div>
230→    );
231→  }
232→
233→  if (isMobile) {
234→    return (
235→      <Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>
236→        <SheetContent
237→          data-sidebar="sidebar"
238→          data-slot="sidebar"
239→          data-mobile="true"
240→          className="bg-sidebar text-sidebar-foreground w-(--sidebar-width) border-0 p-0 [&>button]:hidden"
241→          style={
242→            {
243→              "--sidebar-width": SIDEBAR_WIDTH_MOBILE,
244→            } as React.CSSProperties
245→          }
246→          side={side}
247→        >
248→          <SheetHeader className="sr-only">
249→            <SheetTitle>Sidebar</SheetTitle>
250→            <SheetDescription>Displays the mobile sidebar.</SheetDescription>
251→          </SheetHeader>
252→          <div className="flex h-full w-full flex-col">{children}</div>
253→        </SheetContent>
254→      </Sheet>
255→    );
256→  }
257→
258→  return (
259→    <div
260→      className="group peer text-sidebar-foreground hidden md:block"
261→      data-state={state}
262→      data-collapsible={state === "collapsed" ? collapsible : ""}
263→      data-hover-reveal={hoverOpen ? "true" : "false"}
264→      data-variant={variant}
265→      data-side={side}
266→      data-slot="sidebar"
267→    >
268→      {enableHoverReveal && (
269→        <div
270→          data-slot="sidebar-hover-zone"
271→          className={cn(
272→            "fixed inset-y-0 z-30 w-2 bg-transparent",
273→            side === "left" ? "left-0" : "right-0"
274→          )}
275→          onPointerEnter={openHover}
276→          onPointerLeave={closeHover}
277→        />
278→      )}
279→      {hoverOpen && (
280→        <div
281→          data-slot="sidebar-backdrop"
282→          className="fixed inset-0 z-20"
283→          onClick={() => setHoverOpen(false)}
284→          aria-hidden="true"
285→        />
286→      )}
287→      {/* This is what handles the sidebar gap on desktop */}
288→      <div
289→        data-slot="sidebar-gap"
290→        className={cn(
291→          "relative w-(--sidebar-width) bg-transparent transition-[width] ease-[cubic-bezier(.19,1,.22,1)]",
292→          state === "expanded" ? "duration-[280ms]" : "duration-[200ms]",
293→          "group-data-[collapsible=offcanvas]:w-0",
294→          "group-data-[side=right]:rotate-180"
295→        )}
296→      />
297→      <div
298→        data-slot="sidebar-container"
299→        className={cn(
300→          "fixed inset-y-0 z-10 hidden w-(--sidebar-width) transition-[left,right,width,opacity,translate] md:flex",
