  1→import React from "react";
  2→import { match } from "ts-pattern";
  3→import type { WorkspaceStatus } from "@shared/enums";
  4→
  5→interface WorkflowStatusIconProps {
  6→  status: WorkspaceStatus;
  7→  size?: number;
  8→  className?: string;
  9→}
 10→
 11→/** Partial arc circle used by in-progress and in-review statuses. */
 12→function ProgressCircle({
 13→  cx,
 14→  cy,
 15→  r,
 16→  c,
 17→  fraction,
 18→  color,
 19→}: {
 20→  cx: number;
 21→  cy: number;
 22→  r: number;
 23→  c: number;
 24→  fraction: number;
 25→  color: string;
 26→}) {
 27→  return (
 28→    <>
 29→      <circle cx={cx} cy={cy} r={r} stroke={color} strokeWidth={1.5} opacity={0.3} />
 30→      <circle
 31→        cx={cx}
 32→        cy={cy}
 33→        r={r}
 34→        stroke={color}
 35→        strokeWidth={1.5}
 36→        strokeDasharray={`${c * fraction} ${c}`}
 37→        strokeDashoffset={c * 0.25}
 38→        strokeLinecap="round"
 39→        transform={`rotate(-90 ${cx} ${cy})`}
 40→      />
 41→    </>
 42→  );
 43→}
 44→
 45→/**
 46→ * Workflow status icons.
 47→ *
 48→ * Backlog     → dashed circle (gray)
 49→ * In Progress → half-filled circle (amber)
 50→ * In Review   → 3/4 filled circle (purple)
 51→ * Done        → filled circle + checkmark (green)
 52→ * Canceled    → circle + diagonal line (gray)
 53→ */
 54→export const WorkflowStatusIcon = React.memo(function WorkflowStatusIcon({
 55→  status,
 56→  size = 14,
 57→  className,
 58→}: WorkflowStatusIconProps) {
 59→  const half = size / 2;
 60→  const r = half - 1.5; // radius with stroke inset
 61→  const circumference = 2 * Math.PI * r;
 62→
 63→  return (
 64→    <svg
 65→      width={size}
 66→      height={size}
 67→      viewBox={`0 0 ${size} ${size}`}
 68→      fill="none"
 69→      className={className}
 70→      aria-label={status}
 71→    >
 72→      {match(status)
 73→        .with("backlog", () => (
 74→          <circle
 75→            cx={half}
 76→            cy={half}
 77→            r={r}
 78→            stroke="var(--muted-foreground)"
 79→            strokeWidth={1.5}
 80→            strokeDasharray="2 2.5"
 81→            opacity={0.6}
 82→          />
 83→        ))
 84→        .with("in-progress", () => (
 85→          <ProgressCircle
 86→            cx={half}
 87→            cy={half}
 88→            r={r}
 89→            c={circumference}
 90→            fraction={0.5}
 91→            color="var(--status-in-progress)"
 92→          />
 93→        ))
 94→        .with("in-review", () => (
 95→          <ProgressCircle
 96→            cx={half}
 97→            cy={half}
 98→            r={r}
 99→            c={circumference}
100→            fraction={0.75}
101→            color="var(--status-in-review)"
102→          />
103→        ))
104→        .with("done", () => {
105→          // Filled circle + checkmark
106→          const checkScale = size / 14;
107→          return (
108→            <>
109→              <circle cx={half} cy={half} r={r} fill="var(--status-done)" />
110→              <path
111→                d={`M${4 * checkScale} ${7 * checkScale} L${6.5 * checkScale} ${9.5 * checkScale} L${10 * checkScale} ${4.5 * checkScale}`}
112→                stroke="var(--background)"
113→                strokeWidth={1.5}
114→                strokeLinecap="round"
115→                strokeLinejoin="round"
116→                fill="none"
117→              />
118→            </>
119→          );
120→        })
121→        .with("canceled", () => (
122→          // Circle + diagonal line
123→          <>
124→            <circle
125→              cx={half}
126→              cy={half}
127→              r={r}
128→              stroke="var(--muted-foreground)"
129→              strokeWidth={1.5}
130→              opacity={0.4}
131→            />
132→            <line
133→              x1={half - r * 0.5}
134→              y1={half - r * 0.5}
135→              x2={half + r * 0.5}
136→              y2={half + r * 0.5}
137→              stroke="var(--muted-foreground)"
138→              strokeWidth={1.5}
139→              strokeLinecap="round"
140→              opacity={0.6}
141→            />
142→          </>
143→        ))
144→        .exhaustive()}
145→    </svg>
146→  );
147→});
